  // Implementation of the HSV conversion formula
}

// Function to apply the color threshold
void applyThreshold(Pixel *pixel, int minHue, int maxHue, int minSat, int maxSat, int minVal, int maxVal) {
  float h, s, v;
  convertToHSV(pixel, &h, &s, &v);
  if (h >= minHue && h <= maxHue && s >= minSat && s <= maxSat && v >= minVal && v <= maxVal) {
    pixel->r = 255;
    pixel->g = 255;
    pixel->b = 255;
  } else {
    pixel->r = 0;
    pixel->g = 0;
    pixel->b = 0;
  }
}

int main() {
  // Load the image
  Pixel *image = (Pixel *)malloc(100 * 100 * sizeof(Pixel));

  // Apply the threshold
  for (int i = 0; i < 100 * 100; i++) {
    applyThreshold(&image[i], 0, 180, 0, 255, 0, 255);
  }

  // Display the thresholded image
  for (int i = 0; i < 100 * 100; i++) {
    printf("%d %d %d\n", image[i].r, image[i].g, image[i].b);
  }

  return 0;
}
